const raw = $input.first().json;
const d = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const mermaidCode = d.mermaidCode || '';
const processes = d.processes || [];

if (!mermaidCode) {
  return { json: { diagramUrl: '', error: 'No mermaidCode provided', processCount: processes.length } };
}

// Base64url-encode the Mermaid code for mermaid.ink
const encoded = Buffer.from(mermaidCode).toString('base64')
  .replace(/\+/g, '-').replace(/\//g, '_').replace(/=/g, '');

const inkPngUrl = `https://mermaid.ink/img/${encoded}`;
const inkSvgUrl = `https://mermaid.ink/svg/${encoded}`;

// Supabase Storage config — set these as n8n environment variables
// (n8n Settings → Variables: SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY)
const supabaseUrl = $env.SUPABASE_URL || '';
const supabaseKey = $env.SUPABASE_SERVICE_ROLE_KEY || '';

if (!supabaseUrl || !supabaseKey) {
  // No Supabase config — fall back to mermaid.ink SVG URL (no upload)
  return { json: { diagramUrl: inkSvgUrl, source: 'mermaid.ink', processCount: processes.length } };
}

// Fetch PNG from mermaid.ink
let pngBuffer;
try {
  const pngResponse = await $helpers.httpRequest({
    method: 'GET',
    url: inkPngUrl,
    encoding: 'arraybuffer',
    returnFullResponse: true,
    timeout: 15000,
  });
  if (pngResponse.statusCode >= 200 && pngResponse.statusCode < 300 && pngResponse.body) {
    pngBuffer = Buffer.from(pngResponse.body);
  }
} catch (fetchErr) {
  // mermaid.ink unavailable — fall back to SVG URL
  return { json: { diagramUrl: inkSvgUrl, source: 'mermaid.ink-fallback', processCount: processes.length, fetchError: fetchErr.message } };
}

if (!pngBuffer || pngBuffer.length === 0) {
  return { json: { diagramUrl: inkSvgUrl, source: 'mermaid.ink-fallback', processCount: processes.length } };
}

// Upload PNG to Supabase Storage (diagrams bucket)
const objectName = `diagram-${Date.now()}-${Math.random().toString(36).slice(2)}.png`;
const uploadUrl = `${supabaseUrl}/storage/v1/object/diagrams/${objectName}`;

try {
  const uploadResponse = await $helpers.httpRequest({
    method: 'POST',
    url: uploadUrl,
    headers: {
      Authorization: `Bearer ${supabaseKey}`,
      'Content-Type': 'image/png',
      'x-upsert': 'true',
    },
    body: pngBuffer,
    returnFullResponse: true,
    timeout: 15000,
  });

  if (uploadResponse.statusCode >= 200 && uploadResponse.statusCode < 300) {
    const permanentUrl = `${supabaseUrl}/storage/v1/object/public/diagrams/${objectName}`;
    return { json: { diagramUrl: permanentUrl, source: 'supabase-storage', processCount: processes.length } };
  } else {
    // Upload failed — fall back to mermaid.ink SVG
    return { json: { diagramUrl: inkSvgUrl, source: 'mermaid.ink-fallback', processCount: processes.length, uploadStatus: uploadResponse.statusCode } };
  }
} catch (uploadErr) {
  return { json: { diagramUrl: inkSvgUrl, source: 'mermaid.ink-fallback', processCount: processes.length, uploadError: uploadErr.message } };
}
